={{ JSON.stringify((() => {
  const source = $json.rules_output?.resolver_input?.product_context;
  const product_context = source && typeof source === 'object' && !Array.isArray(source) ? source : {};
  const constraints = {};

  if (typeof product_context.brand === 'string' && product_context.brand.trim()) {
    constraints.brand = product_context.brand.trim();
  }
  if (typeof product_context.model === 'string' && product_context.model.trim()) {
    constraints.model = product_context.model.trim();
  }
  if (typeof product_context.storage === 'string' && product_context.storage.trim()) {
    constraints.storage = product_context.storage.trim();
  }
  if (typeof product_context.condition === 'string' && product_context.condition.trim()) {
    constraints.condition = product_context.condition.trim();
  }

  const budget = Number(product_context.budget_etb);
  if (Number.isFinite(budget)) {
    constraints.budget_etb = budget;
  }

  const sellerIdCandidates = [
    $json.session?.client_config?.seller_id,
    $json.client_config?.seller_id,
    $json.client_config?.sellerId,
    $env.SELLER_ID,
  ];
  const sellerId = sellerIdCandidates.find((value) => typeof value === 'string' && value.trim());

  return {
    sellerId: sellerId ? String(sellerId).trim() : '',
    constraints,
  };
})()) }}

