const input = $json ?? {};
const isRecord = (value) => !!value && typeof value === 'object' && !Array.isArray(value);
const base = {
  event: isRecord(input.event) ? input.event : {},
  session: isRecord(input.session) ? input.session : {},
  client_config: isRecord(input.client_config) ? input.client_config : {},
  understanding_output: isRecord(input.understanding_output) ? input.understanding_output : {},
  understanding_meta: isRecord(input.understanding_meta) ? input.understanding_meta : {},
  rules_output: isRecord(input.rules_output) ? input.rules_output : {},
};

const convex_response = isRecord(input.convex_response) ? input.convex_response : {};
const products = Array.isArray(convex_response.products) ? convex_response.products : [];
const countValue = typeof convex_response.count === 'number' && Number.isFinite(convex_response.count)
  ? convex_response.count
  : products.length;
const raw_missing_fields = Array.isArray(base.rules_output?.resolver_input?.missing_fields)
  ? base.rules_output.resolver_input.missing_fields
  : [];
const missing_fields = products.length > 0 ? [] : raw_missing_fields;

return [{
  json: {
    ...base,
    resolver_output: {
      result_mode: products.length > 0 ? 'products_found' : 'no_products',
      products,
      metadata: { count: countValue },
      missing_fields,
      source: 'convex',
    },
  },
}];

parameters.jsonBody:
={{ (() => {
  const blockedKeys = new Set([
    'post_price_mode',
    'result_type',
    'facts_for_reply',
    'variant 1',
    'variant 2',
    'variant 3',
    'variant 4',
    'variant_1',
    'variant_2',
    'variant_3',
    'variant_4',
    'variant1',
    'variant2',
    'variant3',
    'variant4',
  ]);

  const stripLegacyFields = (value) => {
    if (Array.isArray(value)) {
      return value.map(stripLegacyFields);
    }

    if (!value || typeof value !== 'object') {
      return value ?? null;
    }

    const output = {};
    for (const [key, entry] of Object.entries(value)) {
      if (blockedKeys.has(key)) {
        continue;
      }
      output[key] = stripLegacyFields(entry);
    }
    return output;
  };

  const systemPrompt = `
You are a helpful Ethiopian phone seller on Telegram. Speak in natural Amharic.
